def classify(score):
    if score >= 90:        # block by indentation
        return "A"
    elif score >= 80:
        return "B"
    else:
        return "C"

for s in [95, 82, 71]:
    print(s, "->", classify(s))
# 95 -> A / 82 -> B / 71 -> C

scores = {"math": 90, "cs": 95, "art": 72}

for subject, score in scores.items():
    if score >= 90:
        print(f"{subject}: top tier")
    elif score >= 80:
        print(f"{subject}: solid")
    else:
        print(f"{subject}: needs work")
# math: top tier / cs: top tier / art: needs work
